#include <cstdio>
#include <cmath>
#include <omp.h>

#define NX 512
#define NY 512
#define NZ 512
#define STEPS 100

void iso2dfd(float* A, float* B, int nx, int ny, int nz, int steps) {
    for (int step = 0; step < steps; step++) {
        #pragma omp parallel for collapse(3)
        for (int k = 1; k < nz - 1; k++) {
            for (int j = 1; j < ny - 1; j++) {
                for (int i = 1; i < nx - 1; i++) {
                    int idx = k * ny * nx + j * nx + i;
                    B[idx] = (A[idx - nx * ny] + A[idx + nx * ny] +
                              A[idx - nx] + A[idx + nx] +
                              A[idx - 1] + A[idx + 1]) / 6.0f;
                }
            }
        }
        // Swap pointers
        float* temp = A;
        A = B;
        B = temp;
    }
}

int main() {
    float* A = new float[NX * NY * NZ];
    float* B = new float[NX * NY * NZ];

    // Initialize array A with some values
    for (int i = 0; i < NX * NY * NZ; i++) {
        A[i] = static_cast<float>(i % 100);
        B[i] = 0.0f;
    }

    iso2dfd(A, B, NX, NY, NZ, STEPS);

    // Output the sum to verify computation
    double sum = 0.0;
    for (int i = 0; i < NX * NY * NZ; i++) {
        sum += A[i];
    }
    printf("Sum: %f\n", sum);

    delete[] A;
    delete[] B;
    return 0;
}
